      "keystrokes": "python3 - << 'PY'\nfrom pathlib import Path\np = Path('/app/run_stream_analysis_fix.py')\ns = p.read_text()\nold_snip = \"for line in fh:\\n            parts = line.rstrip('\\\\n').split('\\\\t')\\n            if not parts:\\n                continue\\n            gene_token = parts[0].strip('\\\"')\\n            if gene_token in required_set:\\n                vals = parts[1:]\\n                if len(vals) != len(barcodes):\\n                    # skip malformed\\n                    continue\\n                rows.append([int(x.strip('\\\"')) if x.strip('\\\"')!='' else 0 for x in vals])\"\nnew_snip = \"for line in fh:\\n            parts = line.rstrip('\\\\n').split('\\\\t')\\n            if not parts:\\n                continue\\n            gene_token = parts[0].strip('\\\"')\\n            if gene_token in required_set:\\n                vals = parts[1:]\\n                # tolerate mismatched token counts between header and data lines\n                if len(vals) != len(barcodes):\\n                    if len(vals) > len(barcodes):\\n                        # assume extra leading token(s); align using last N tokens\\n                        vals = vals[-len(barcodes):]\\n                    else:\\n                        # fewer tokens than barcodes: left-pad with zeros\\n                        vals = ['0']*(len(barcodes)-len(vals)) + vals\\n                # strip quotes from each token and convert to int (empty -> 0)\n                clean_vals = [int(x.strip('\\\"')) if x.strip('\\\"')!='' else 0 for x in vals]\\n                rows.append(clean_vals)\"\nif old_snip in s:\n    s = s.replace(old_snip, new_snip)\n    p.write_text(s)\n    print('Updated parser to tolerate token-count mismatches and strip quotes from values')\nelse:\n    print('Expected code snippet not found; aborting (file may already be updated)')\nPY\n",
