import pandas as pd
import numpy as np
from sklearn.metrics import roc_auc_score, average_precision_score
from scipy.stats import mannwhitneyu

DATA_DIR = 'data'
# Try to locate expected files in data dir (allow exact or fuzzy matches)
expected_names = {
    'master': ['h_combined_with_flags.xlsx','h_combined_with_flags.xls'],
    'seq': ['sequence_prediction.xlsx','sequence_prediction.xls'],
    'list': ['List_of_proteins_for_comparing_MLO_enrichment.xlsx','List_of_proteins_for_comparing_MLO_enrichment.xls']
}
files = {}
for key, candidates in expected_names.items():
    found = None
    for cand in candidates:
        p = os.path.join(DATA_DIR, cand)
        if os.path.exists(p):
            found = p
            break
    # fallback: try any file in data dir that matches keyword
    if not found:
        for f in os.listdir(DATA_DIR):
            if key.split('_')[0] in f.lower() or 'combined' in f.lower() or 'sequence' in f.lower() or 'list_of_proteins' in f.lower():
                found = os.path.join(DATA_DIR, f)
                break
    files[key] = found

print('Located files:', files)
for k,v in files.items():
    if v is None:
        print(f'ERROR: Could not locate expected file for {k} in {DATA_DIR}. Aborting.')
        sys.exit(2)

# Read files
master = pd.read_excel(files['master'], engine='openpyxl')
seq = pd.read_excel(files['seq'], engine='openpyxl')
# For the list file, header row is row 2 (index 1), per task description
listdf = pd.read_excel(files['list'], sheet_name='Training proteins removed', header=1, engine='openpyxl')

# Helper to find UniprotEntry column
def find_uniprot_col(df):
    for c in df.columns:
        if str(c).strip().lower() in ('uniprotentry','uniprot','uniprot_id','uniprot id','entry'):
            return c
    for c in df.columns:
        if 'uniprot' in str(c).lower():
            return c
    return None

u_master = find_uniprot_col(master)
u_list = find_uniprot_col(listdf)
u_seq = find_uniprot_col(seq)

if u_master is None or u_list is None:
    print('ERROR: Could not find Uniprot columns. Found master:', u_master, 'list:', u_list, 'seq:', u_seq)
    sys.exit(3)

master = master.rename(columns={u_master: 'UniprotEntry'})
listdf = listdf.rename(columns={u_list: 'UniprotEntry'})
if u_seq:
    seq = seq.rename(columns={u_seq: 'UniprotEntry'})

print('Shapes: master', master.shape, 'list', listdf.shape, 'seq', seq.shape)

# Merge
merged = pd.merge(listdf, master, on='UniprotEntry', how='inner')
print('Merged shape:', merged.shape)
if 'UniprotEntry' in seq.columns:
    merged = pd.merge(merged, seq, on='UniprotEntry', how='left', suffixes=(None, '_seq'))
    print('Merged with seq predictors shape:', merged.shape)

# Identify dataset membership columns from the list file
list_cols = [c for c in listdf.columns if c != 'UniprotEntry']
dataset_cols = []
for c in list_cols:
    try:
        vals = pd.to_numeric(listdf[c], errors='coerce')
    except Exception:
        continue
    if int((vals == 1).sum()) > 0:
        dataset_cols.append(c)
print('Dataset membership columns detected (count):', len(dataset_cols))

# Identify predictor columns (heuristic)
possible_predictors = ['PScore','PLAAC','catGRANULE','DeepPhase','DeepCoil','Phos','SaPS','PdPS']
preds = []
for c in merged.columns:
    for p in possible_predictors:
        if p.lower() in str(c).lower():
            preds.append(c)
            break
preds = list(dict.fromkeys(preds))
print('Predictor columns detected:', preds)

# Find negative background flag hNoPS
neg_flag_col = None
for c in master.columns:
    if str(c).lower() == 'hnops' or 'nops' in str(c).lower() or 'no_ps' in str(c).lower() or 'noPS' in str(c):
        neg_flag_col = c
        break
if 'hNoPS' in master.columns:
    neg_flag_col = 'hNoPS'

if neg_flag_col is None:
    print('WARNING: hNoPS not found. Will try to synthesize negatives as proteins not SaPS and not PdPS if available.')
else:
    print('Using negative/background column:', neg_flag_col)

if neg_flag_col is None:
    merged['_is_neg_bg'] = ((merged.get('hSaPS', 0) != 1) & (merged.get('hPdPS', 0) != 1))
    neg_flag_col = '_is_neg_bg'

MIN_POS = 10
results = []
for dcol in dataset_cols:
    if dcol not in merged.columns:
        membership_series = listdf.set_index('UniprotEntry')[dcol]
        membership_series = membership_series.reindex(merged['UniprotEntry']).fillna(0)
        pos_mask = (membership_series == 1)
    else:
        pos_mask = (merged[dcol] == 1)
    npos = int(pos_mask.sum())
    if npos < MIN_POS:
        continue
    neg_mask = (merged[neg_flag_col] == 1) & (~pos_mask)
    nneg = int(neg_mask.sum())
    if nneg < MIN_POS:
        continue
    y = pd.Series(0, index=merged.index)
    y[pos_mask] = 1
    y = y[neg_mask | pos_mask]
    for p in preds:
        if p not in merged.columns:
            continue
        scores = merged.loc[y.index, p]
        valid = scores.replace([np.inf, -np.inf], np.nan).notna()
        if valid.sum() < 5:
            continue
        y_valid = y[valid]
        scores_valid = scores[valid].astype(float)
        if scores_valid.nunique() < 2:
            auc = float('nan')
            ap = float('nan')
        else:
            try:
                auc = roc_auc_score(y_valid, scores_valid)
            except Exception:
                auc = float('nan')
            try:
                ap = average_precision_score(y_valid, scores_valid)
            except Exception:
                ap = float('nan')
        results.append({'dataset': dcol, 'n_pos': npos, 'n_neg': nneg, 'predictor': p, 'roc_auc': auc, 'avg_precision': ap})

resdf = pd.DataFrame(results)
resdf.to_csv('summary_per_dataset_predictor.csv', index=False)

# classify datasets by keywords
mlo_keywords = ['opencell','g3bp','phase','phas','phas','particulate','punctae','punctate','dact1','granule','condensate']
mem_keywords = ['mito','mitochond','amyloid','membran','membrane']

def classify_dataset(name):
    s = str(name).lower()
    for kw in mem_keywords:
        if kw in s:
            return 'membrane'
    for kw in mlo_keywords:
        if kw in s:
            return 'mlo'
    return 'other'

if not resdf.empty:
    resdf['group'] = resdf['dataset'].apply(classify_dataset)
    res_sub = resdf[resdf['group'].isin(['mlo','membrane'])].copy()
    summary = []
    for p in res_sub['predictor'].unique():
        sub = res_sub[res_sub['predictor'] == p]
        mlo_aucs = sub.loc[sub['group']=='mlo','roc_auc'].dropna()
        mem_aucs = sub.loc[sub['group']=='membrane','roc_auc'].dropna()
        mean_mlo = float(mlo_aucs.mean()) if len(mlo_aucs)>0 else float('nan')
        mean_mem = float(mem_aucs.mean()) if len(mem_aucs)>0 else float('nan')
        pval = float('nan')
        try:
            if len(mlo_aucs) >= 3 and len(mem_aucs) >= 3:
                stat, pval = mannwhitneyu(mlo_aucs, mem_aucs, alternative='two-sided')
        except Exception:
            pval = float('nan')
        summary.append({'predictor': p, 'mean_auc_mlo': mean_mlo, 'mean_auc_membrane': mean_mem, 'p_mannwhitney': pval, 'n_mlo_datasets': len(mlo_aucs), 'n_mem_datasets': len(mem_aucs)})
    summary_df = pd.DataFrame(summary)
    summary_df.to_csv('summary_predictor_group_comparison.csv', index=False)
else:
    print('No per-dataset/predictor metrics computed (resdf empty).')

# Write trace.md and answer.txt with key steps and pointers to CSVs
with open('trace.md','w') as fh:
    fh.write('# Analysis Trace\n\n')
    fh.write('See summary_per_dataset_predictor.csv and summary_predictor_group_comparison.csv for numeric results.\n')
    fh.write('\nThis analysis script merged the list-of-proteins membership file with the master predictor table by UniprotEntry, detected predictor columns by name heuristics, computed ROC AUC and average precision per dataset/predictor using hNoPS (or synthesized negatives), and compared MLO vs membrane datasets by keyword classification.\n')

with open('answer.txt','w') as fh:
    if os.path.exists('summary_predictor_group_comparison.csv'):
        sf = pd.read_csv('summary_predictor_group_comparison.csv')
        fh.write('Final comparison of predictor performance on MLO vs membrane datasets\n')
        fh.write('See summary_predictor_group_comparison.csv for the numeric results.\n\n')
        for _, row in sf.iterrows():
            fh.write(f"Predictor: {row['predictor']}\n  mean ROC AUC on MLO datasets = {row['mean_auc_mlo']:.3f} (n={int(row['n_mlo_datasets'])}), mean ROC AUC on membrane datasets = {row['mean_auc_membrane']:.3f} (n={int(row['n_mem_datasets'])}), Mann-Whitney p = {row['p_mannwhitney']}\n\n")
    else:
        fh.write('No comparison results generated. Please inspect trace.md and the scripts.\n')

print('Completed. Outputs: trace.md, answer.txt, summary_per_dataset_predictor.csv, summary_predictor_group_comparison.csv (if computed).')
